import{_ as o,o as a,c as i,a4 as t}from"./chunks/framework.CDpUjPX_.js";const h=JSON.parse('{"title":"Integracoes OSINT","description":"","frontmatter":{},"headers":[],"relativePath":"api/osint-integrations.md","filePath":"api/osint-integrations.md"}'),r={name:"api/osint-integrations.md"};function s(c,e,n,d,l,g){return a(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="integracoes-osint" tabindex="-1">Integracoes OSINT <a class="header-anchor" href="#integracoes-osint" aria-label="Permalink to &quot;Integracoes OSINT&quot;">​</a></h1><p>Servicos externos integrados ao Kubex para enriquecer investigacoes de pirataria.</p><h2 id="registro-br-rdap-t1-1" tabindex="-1">Registro.br RDAP (T1.1) <a class="header-anchor" href="#registro-br-rdap-t1-1" aria-label="Permalink to &quot;Registro.br RDAP (T1.1)&quot;">​</a></h2><ul><li><strong>Servico:</strong> <code>app/services/rdap_br_service.py</code></li><li><strong>API:</strong> <code>GET https://rdap.registro.br/domain/{domain}</code></li><li><strong>Auth:</strong> Nenhuma (API publica)</li><li><strong>Cache:</strong> Redis 7 dias (<code>kubex:rdap_br:{domain}</code>)</li><li><strong>Integracao:</strong> Prioridade em <code>get_abuse_contact_async()</code> para dominios .br</li><li><strong>Dados:</strong> Registrante, CNPJ/CPF, abuse email, nameservers, data de registro</li></ul><h2 id="brasilapi-t1-2" tabindex="-1">BrasilAPI (T1.2) <a class="header-anchor" href="#brasilapi-t1-2" aria-label="Permalink to &quot;BrasilAPI (T1.2)&quot;">​</a></h2><ul><li><strong>Servico:</strong> <code>app/services/brasil_api_service.py</code></li><li><strong>API:</strong> <code>GET https://brasilapi.com.br/api/cnpj/v1/{cnpj}</code></li><li><strong>Auth:</strong> Nenhuma</li><li><strong>Cache:</strong> Redis 7 dias (<code>kubex:brasilapi:cnpj:{cnpj}</code>)</li><li><strong>Circuit breaker:</strong> <code>brasilapi_circuit</code> (5 failures → OPEN 5min)</li><li><strong>Dados:</strong> Razao social, nome fantasia, situacao cadastral, socios (QSA), endereco</li></ul><h2 id="intel-extractor-t1-3" tabindex="-1">Intel Extractor (T1.3) <a class="header-anchor" href="#intel-extractor-t1-3" aria-label="Permalink to &quot;Intel Extractor (T1.3)&quot;">​</a></h2><ul><li><strong>Engine:</strong> <code>app/engines/intel_extractor.py</code></li><li><strong>Funcao:</strong> <code>extract_identifiers(text) -&gt; list[IdentifierMatch]</code></li><li><strong>Identifica:</strong> CPF, CNPJ, PIX, Bitcoin, Ethereum, .onion, emails, telefones BR</li><li><strong>Tabela:</strong> <code>piracy_intelligence</code> (pool compartilhado, sem tenant)</li><li><strong>Uso:</strong> Pos-crawl do Crawler e SourceIntel</li></ul><h2 id="metadata-extraction-t1-4" tabindex="-1">Metadata Extraction (T1.4) <a class="header-anchor" href="#metadata-extraction-t1-4" aria-label="Permalink to &quot;Metadata Extraction (T1.4)&quot;">​</a></h2><ul><li><strong>Servico:</strong> <code>app/services/image_processor.py</code></li><li><strong>Funcao:</strong> <code>extract_metadata(img_bytes) -&gt; dict</code></li><li><strong>Dados:</strong> EXIF (software, data, camera, GPS, copyright)</li><li><strong>Campo:</strong> <code>alerts.metadata_json</code> (JSONB)</li></ul><h2 id="wayback-machine-t1-5" tabindex="-1">Wayback Machine (T1.5) <a class="header-anchor" href="#wayback-machine-t1-5" aria-label="Permalink to &quot;Wayback Machine (T1.5)&quot;">​</a></h2><ul><li><strong>Engine:</strong> <code>app/engines/takedown_engine.py</code></li><li><strong>Funcao:</strong> <code>archive_evidence(url) -&gt; str | None</code></li><li><strong>API:</strong> <code>POST https://web.archive.org/save/{url}</code></li><li><strong>Campo:</strong> <code>takedowns.archive_url</code></li><li><strong>Comportamento:</strong> Non-blocking — falha nao impede takedown</li></ul><h2 id="google-dorks-brasileiros-t1-6" tabindex="-1">Google Dorks Brasileiros (T1.6) <a class="header-anchor" href="#google-dorks-brasileiros-t1-6" aria-label="Permalink to &quot;Google Dorks Brasileiros (T1.6)&quot;">​</a></h2><ul><li><strong>Metodo:</strong> CrawlTarget rows com <code>scrape_method=&quot;google_site&quot;</code></li><li><strong>Targets:</strong> Mercado Livre, OLX, Shopee, Amazon, Google Drive, Mega.nz, MediaFire, Telegram, Linktree, Beacons</li><li><strong>Motor:</strong> BrandWatch (name search) gera queries <code>site:{template} &quot;{nome}&quot;</code></li></ul><h2 id="yandex-baidu-images-t1-7" tabindex="-1">Yandex + Baidu Images (T1.7) <a class="header-anchor" href="#yandex-baidu-images-t1-7" aria-label="Permalink to &quot;Yandex + Baidu Images (T1.7)&quot;">​</a></h2><ul><li><strong>Config:</strong> <code>MOTOR1_YANDEX_ENABLED=true</code>, <code>MOTOR1_BAIDU_ENABLED=false</code></li><li><strong>Via SerpAPI:</strong> <code>engine=yandex_images</code>, <code>engine=baidu</code></li><li><strong>Circuit breakers:</strong> <code>yandex_circuit</code>, <code>baidu_circuit</code></li><li><strong>Cascade:</strong> Adicionados ao <code>search_image()</code> gather junto com SerpAPI e Social Reverse</li></ul><hr><h2 id="tier-2" tabindex="-1">Tier 2 <a class="header-anchor" href="#tier-2" aria-label="Permalink to &quot;Tier 2&quot;">​</a></h2><h3 id="maigret-—-username-search-t2-1" tabindex="-1">Maigret — Username Search (T2.1) <a class="header-anchor" href="#maigret-—-username-search-t2-1" aria-label="Permalink to &quot;Maigret — Username Search (T2.1)&quot;">​</a></h3><ul><li><strong>Engine:</strong> <code>app/engines/maigret_engine.py</code></li><li><strong>Funcao:</strong> <code>search_username(username: str) -&gt; list[MaigretResult]</code></li><li><strong>Execucao:</strong> Subprocess async (<code>asyncio.create_subprocess_exec</code>) — Maigret roda como CLI Python</li><li><strong>Config:</strong> <code>MAIGRET_ENABLED=true</code>, <code>MAIGRET_TIMEOUT=120</code> (segundos por busca)</li><li><strong>Sites cobertos:</strong> 3000+ sites (redes sociais, forums, marketplaces, plataformas adultas)</li><li><strong>Admin endpoint:</strong> <code>POST /api/v1/admin/osint/maigret</code> — body <code>{&quot;username&quot;: &quot;string&quot;}</code></li><li><strong>Dados retornados:</strong> Lista de <code>{site, url, found: bool, category, http_status}</code> por perfil encontrado</li><li><strong>Armazenamento:</strong> Resultados gravados em <code>piracy_intelligence</code> com <code>source=&quot;maigret&quot;</code></li><li><strong>Integracao:</strong> Chamado automaticamente pos-crawl quando <code>intel_extractor</code> detecta username em texto</li></ul><h3 id="changedetection-io-t2-2" tabindex="-1">ChangeDetection.io (T2.2) <a class="header-anchor" href="#changedetection-io-t2-2" aria-label="Permalink to &quot;ChangeDetection.io (T2.2)&quot;">​</a></h3><ul><li><strong>Servico:</strong> <code>app/services/changedetection_service.py</code></li><li><strong>Docker:</strong> Container <code>changedetection</code> na porta <code>5000</code> (interno), acessivel via <code>http://changedetection:5000</code></li><li><strong>Config:</strong> <code>CHANGEDETECTION_URL=http://changedetection:5000</code>, <code>CHANGEDETECTION_API_KEY</code> (obrigatorio em prod)</li><li><strong>Funcoes:</strong><ul><li><code>add_watch(url: str, tag: str) -&gt; str</code> — adiciona URL para monitoramento, retorna <code>watch_uuid</code></li><li><code>remove_watch(uuid: str) -&gt; bool</code> — remove watch por UUID</li><li><code>get_diff(uuid: str) -&gt; ChangeDiff | None</code> — retorna diff do ultimo check (texto alterado, screenshot diff)</li><li><code>list_watches() -&gt; list[WatchInfo]</code> — lista todos os watches ativos com status</li></ul></li><li><strong>Integracao Celery:</strong> Task <code>check_changedetection_diffs</code> no beat (intervalo: 30 min) — busca diffs novos e cria <code>Alert</code> para o usuario dono da URL monitorada</li><li><strong>Dados retornados:</strong> <code>{uuid, url, last_checked, has_change, diff_text, diff_screenshot_url}</code></li></ul><h3 id="marketplace-monitor-t2-3" tabindex="-1">Marketplace Monitor (T2.3) <a class="header-anchor" href="#marketplace-monitor-t2-3" aria-label="Permalink to &quot;Marketplace Monitor (T2.3)&quot;">​</a></h3><ul><li><strong>Engine:</strong> <code>app/engines/marketplace_monitor.py</code></li><li><strong>Sites cobertos:</strong> Mercado Livre, OLX, Shopee, Amazon Brasil</li><li><strong>Funcao principal:</strong> <code>scan_marketplace(query: str, site: MarketplaceSite) -&gt; list[MarketplaceListing]</code></li><li><strong>Celery Beat:</strong> Task <code>scan_marketplaces</code> — intervalo configuravel por plano (Pro: 6h, Premium: 1h)</li><li><strong>Crawler:</strong> Usa Crawler (<code>app/engines/crawler/service.py</code>) com <code>AsyncFetcher</code> — respeita <code>KUBEXBOT_RESPECT_ROBOTS_TXT</code></li><li><strong>Extratores por site:</strong><ul><li>Mercado Livre: <code>app/engines/marketplace/mercadolivre_extractor.py</code> — CSS selectors + paginacao ate depth 3</li><li>OLX: <code>app/engines/marketplace/olx_extractor.py</code> — JSON-LD embedded no HTML</li><li>Shopee: <code>app/engines/marketplace/shopee_extractor.py</code> — API GraphQL interna (endpoint <code>/api/v4/search/search_items</code>)</li><li>Amazon BR: <code>app/engines/marketplace/amazon_extractor.py</code> — CSS selectors, ASIN como ID unico</li></ul></li><li><strong>Config:</strong> <code>MARKETPLACE_MONITOR_ENABLED=true</code>, <code>MARKETPLACE_MAX_PAGES=5</code>, <code>MARKETPLACE_SIMILARITY_THRESHOLD=0.75</code></li><li><strong>Dados retornados:</strong> <code>{title, price, seller, url, thumbnail_url, site, listing_id, similarity_score}</code></li><li><strong>Deduplicacao:</strong> <code>listing_id</code> unico por site — evita alertas duplicados em scans consecutivos</li></ul><h3 id="urlscan-io-t2-4" tabindex="-1">urlscan.io (T2.4) <a class="header-anchor" href="#urlscan-io-t2-4" aria-label="Permalink to &quot;urlscan.io (T2.4)&quot;">​</a></h3><ul><li><strong>Servico:</strong> <code>app/services/urlscan_service.py</code></li><li><strong>API:</strong> <code>POST https://urlscan.io/api/v1/scan/</code> (submissao) + <code>GET https://urlscan.io/api/v1/result/{uuid}/</code> (resultado)</li><li><strong>Auth:</strong> Header <code>API-Key: {URLSCAN_API_KEY}</code></li><li><strong>Config:</strong> <code>URLSCAN_API_KEY</code> (obrigatorio em prod), <code>URLSCAN_VISIBILITY=unlisted</code> (default — nao aparece em buscas publicas)</li><li><strong>Funcoes:</strong><ul><li><code>submit_scan(url: str) -&gt; str</code> — submete URL, retorna <code>scan_uuid</code></li><li><code>get_result(uuid: str, timeout: int = 60) -&gt; UrlscanResult | None</code> — polling ate resultado disponivel</li><li><code>scan_and_wait(url: str) -&gt; UrlscanResult | None</code> — helper que combina submit + get_result</li></ul></li><li><strong>Admin endpoint:</strong> <code>POST /api/v1/admin/osint/urlscan</code> — body <code>{&quot;url&quot;: &quot;string&quot;}</code> — dispara scan e retorna resultado</li><li><strong>Cache:</strong> Redis 24h (<code>kubex:urlscan:{sha256_url}</code>) — evita re-escaneamento de mesma URL</li><li><strong>Dados retornados:</strong><ul><li><code>screenshot_url</code> — screenshot da pagina no momento do scan</li><li><code>technologies[]</code> — stack detectada (ex: WordPress, Cloudflare, WooCommerce)</li><li><code>is_behind_cloudflare: bool</code> — detectado via tecnologias ou ASN</li><li><code>ip</code>, <code>country</code>, <code>asn</code>, <code>tls_issuer</code></li><li><code>dom_size</code>, <code>requests_count</code>, <code>console_errors[]</code></li><li><code>verdicts.overall.score</code> — score de maliciosidade (0-100)</li></ul></li></ul><h3 id="dns-intel-t2-5" tabindex="-1">DNS Intel (T2.5) <a class="header-anchor" href="#dns-intel-t2-5" aria-label="Permalink to &quot;DNS Intel (T2.5)&quot;">​</a></h3><ul><li><strong>Servico:</strong> <code>app/services/dns_intel_service.py</code></li><li><strong>Funcao principal:</strong> <code>enrich_domain(domain: str) -&gt; DnsIntelResult</code></li><li><strong>Fontes:</strong><ul><li><strong>SecurityTrails:</strong> <code>GET https://api.securitytrails.com/v1/domain/{domain}</code> — historico DNS, subdomains, IPs historicos</li><li><strong>crt.sh:</strong> <code>GET https://crt.sh/?q=%.{domain}&amp;output=json</code> — certificados SSL emitidos (passivo, sem auth)</li></ul></li><li><strong>Config:</strong> <code>SECURITYTRAILS_API_KEY</code> (obrigatorio para historico DNS — crt.sh e publico)</li><li><strong>Cache:</strong> Redis 24h (<code>kubex:dns_intel:{domain}</code>) — SecurityTrails tem quota limitada</li><li><strong>Admin endpoint:</strong> <code>GET /api/v1/admin/osint/dns-intel?domain={domain}</code></li><li><strong>Dados retornados:</strong><ul><li><code>current_a_records[]</code>, <code>current_mx_records[]</code>, <code>current_ns[]</code></li><li><code>historical_ips[]</code> — IPs anteriores com datas (util para bypass Cloudflare)</li><li><code>subdomains[]</code> — subdomains conhecidos via SecurityTrails</li><li><code>ssl_certificates[]</code> — <code>{issuer, common_name, not_before, not_after, fingerprint}</code> via crt.sh</li><li><code>registrar</code>, <code>whois_created</code>, <code>whois_expires</code></li></ul></li></ul><hr><h2 id="shieldai-—-adult-content-protection-ncii" tabindex="-1">ShieldAI — Adult Content Protection / NCII <a class="header-anchor" href="#shieldai-—-adult-content-protection-ncii" aria-label="Permalink to &quot;ShieldAI — Adult Content Protection / NCII&quot;">​</a></h2><h3 id="shieldai-adult-site-crawler" tabindex="-1">ShieldAI: Adult Site Crawler <a class="header-anchor" href="#shieldai-adult-site-crawler" aria-label="Permalink to &quot;ShieldAI: Adult Site Crawler&quot;">​</a></h3><ul><li><strong>Engine:</strong> <code>app/engines/adult_site_crawler.py</code></li><li><strong>Funcao:</strong> <code>crawl_adult_site(url, query, site_category) -&gt; list[AdultCrawlResult]</code></li><li><strong>Sites:</strong> 65+ sites em 9 categorias (tubes, leak aggregators, escorts, forums, etc.)</li><li><strong>Estrategia:</strong> Crawl por categoria com delays e fetchers diferentes</li><li><strong>Celery Beat:</strong> <code>trigger_adult_crawler</code> a cada 6h</li></ul><h3 id="shieldaic-ncii-detection" tabindex="-1">ShieldAIC: NCII Detection <a class="header-anchor" href="#shieldaic-ncii-detection" aria-label="Permalink to &quot;ShieldAIC: NCII Detection&quot;">​</a></h3><ul><li><strong>Servico:</strong> <code>app/services/ncii_detection_service.py</code></li><li><strong>Deteccao:</strong> pHash matching contra ContentHash registrados</li><li><strong>Face matching:</strong> Comparacao via KubexFaceIndex (Milvus HNSW, cosine similarity)</li><li><strong>Alerta:</strong> <code>is_ncii_case=true</code>, <code>site_category</code>, <code>detected_via</code>, <code>confidence_score</code></li></ul><h3 id="shieldaid-ncii-takedown" tabindex="-1">ShieldAID: NCII Takedown <a class="header-anchor" href="#shieldaid-ncii-takedown" aria-label="Permalink to &quot;ShieldAID: NCII Takedown&quot;">​</a></h3><ul><li><strong>Servico:</strong> <code>app/services/ncii_takedown_service.py</code></li><li><strong>Templates:</strong> Art. 21 Marco Civil (PT), DMCA (EN), Escort Removal (PT/EN)</li><li><strong>Selecao:</strong> Automatica por dominio (.br → Art. 21) e categoria (escort → template especifico)</li><li><strong>SaferNet:</strong> <code>https://new.safernet.org.br/denuncie</code></li><li><strong>Admin:</strong> <code>GET /api/v1/admin/discovery/motor27/stats</code></li></ul><h3 id="shieldai-—-client-api" tabindex="-1">ShieldAI — Client API <a class="header-anchor" href="#shieldai-—-client-api" aria-label="Permalink to &quot;ShieldAI — Client API&quot;">​</a></h3><ul><li><strong>Router:</strong> <code>app/api/v1/ncii.py</code> — 7 user-facing endpoints</li><li><strong>Endpoints:</strong><ul><li><code>GET /api/v1/ncii/alerts</code> — Lista alertas NCII do usuario</li><li><code>GET /api/v1/ncii/stats</code> — Estatisticas de protecao</li><li><code>POST /api/v1/ncii/consent</code> — Consentimento LGPD biometrico</li><li><code>DELETE /api/v1/ncii/consent</code> — Revogar consentimento</li><li><code>GET /api/v1/ncii/consent</code> — Status do consentimento</li><li><code>POST /api/v1/ncii/alerts/{id}/takedown</code> — Solicitar takedown</li><li><code>GET /api/v1/ncii/kit-bo</code> — Gerar Kit B.O. (PDF)</li></ul></li><li><strong>Kit B.O.:</strong> <code>app/services/kit_bo_service.py</code> — PDF com evidencias para delegacia (fpdf2)</li><li><strong>Consent:</strong> <code>app/models/face_search_consent.py</code> — Tracking LGPD Art. 11</li><li><strong>Frontend:</strong> <code>/dashboard/protecao</code> — Dashboard de protecao do cliente</li></ul><hr><h2 id="kubexfaceindex" tabindex="-1">KubexFaceIndex <a class="header-anchor" href="#kubexfaceindex" aria-label="Permalink to &quot;KubexFaceIndex&quot;">​</a></h2><h3 id="banco-de-face-embeddings" tabindex="-1">Banco de Face Embeddings <a class="header-anchor" href="#banco-de-face-embeddings" aria-label="Permalink to &quot;Banco de Face Embeddings&quot;">​</a></h3><ul><li><strong>Engine:</strong> <code>app/engines/face_index.py</code> — Milvus collection <code>kubex_web_faces</code></li><li><strong>Ingestao:</strong> <code>app/services/face_index_ingest.py</code> — extrai faces de imagens crawleadas</li><li><strong>Dimensao:</strong> 512 (InsightFace AntelopeV2)</li><li><strong>Index:</strong> HNSW (M=16, efConstruction=200, COSINE)</li><li><strong>Particoes:</strong> tube_sites, leak_sites, escort_sites, forums, imageboards, social_media, general_web</li></ul><h3 id="metadata-postgresql" tabindex="-1">Metadata PostgreSQL <a class="header-anchor" href="#metadata-postgresql" aria-label="Permalink to &quot;Metadata PostgreSQL&quot;">​</a></h3><ul><li><code>web_face_sources</code> — URLs onde cada rosto foi encontrado</li><li><code>face_index_stats</code> — Estatisticas diarias agregadas</li></ul><h3 id="api-usuario" tabindex="-1">API Usuario <a class="header-anchor" href="#api-usuario" aria-label="Permalink to &quot;API Usuario&quot;">​</a></h3><ul><li><code>POST /api/v1/face-search/web</code> — Busca facial no indice (requer plano Pro+, consentimento LGPD)</li><li>Retorna: matches com URLs, categorias, confianca, status</li></ul><h3 id="api-admin" tabindex="-1">API Admin <a class="header-anchor" href="#api-admin" aria-label="Permalink to &quot;API Admin&quot;">​</a></h3><ul><li><code>GET /api/v1/admin/face-index/stats</code> — Estatisticas do indice</li><li><code>GET /api/v1/admin/face-index/health</code> — Saude do Milvus</li><li><code>GET /api/v1/admin/face-index/top-domains</code> — Top 20 dominios</li><li><code>POST /api/v1/admin/face-index/force-stats</code> — Forcar recalculo</li><li><code>POST /api/v1/admin/face-index/force-dedup</code> — Forcar dedup</li></ul><h3 id="celery-tasks" tabindex="-1">Celery Tasks <a class="header-anchor" href="#celery-tasks" aria-label="Permalink to &quot;Celery Tasks&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Task</th><th>Intervalo</th><th>Queue</th></tr></thead><tbody><tr><td><code>face_index.daily_stats</code></td><td>24h</td><td>celery_face</td></tr><tr><td><code>face_index.verify_urls</code></td><td>7 dias</td><td>celery_face</td></tr><tr><td><code>face_index.cleanup_dead</code></td><td>30 dias</td><td>celery_face</td></tr></tbody></table><h3 id="frontend-admin" tabindex="-1">Frontend Admin <a class="header-anchor" href="#frontend-admin" aria-label="Permalink to &quot;Frontend Admin&quot;">​</a></h3><ul><li><code>/admin/face-index</code> — Dashboard com KPIs, charts, top domains, health</li></ul><hr><h2 id="pipeline-de-busca-unificado-lens" tabindex="-1">Pipeline de Busca Unificado (Lens) <a class="header-anchor" href="#pipeline-de-busca-unificado-lens" aria-label="Permalink to &quot;Pipeline de Busca Unificado (Lens)&quot;">​</a></h2><p>O PIB e o KubexFaceIndex sao integrados diretamente no pipeline do Lens (<code>run_image_search</code>), executando apos a coleta de resultados SerpAPI:</p><ul><li><strong>PIB Check:</strong> batch query por dominio contra <code>piracy_intelligence</code> — enriquece score (+0.05) e exibe badge no frontend</li><li><strong>FaceIndex Search:</strong> detecta rostos na imagem de upload via InsightFace → busca coseno no Milvus — retorna <code>source=&quot;face_match&quot;</code> mesmo para fotos diferentes</li></ul><p>Ver documentacao completa em <a href="/motores/pipeline-busca-unificado">Pipeline de Busca Unificado</a>.</p>',57)])])}const p=o(r,[["render",s]]);export{h as __pageData,p as default};
